import json

def lambda_handler(event, context):
    request = event["Records"][0]["cf"]["request"]
    headers = request.get("headers", {})

    enrich_headers = headers.get("x-enrich-url", [])
    enriched_data = []

    try:
        import requests
    except Exception as e:
        request.setdefault("headers", {})
        request["headers"]["x-enrich-error"] = [{
            "key": "X-Enrich-Error",
            "value": "requests import failed"
        }]
        return request

    for header in enrich_headers:
        url = header.get("value", "").strip()
        if not url:
            continue
        try:
            resp = requests.get(url, timeout=2)
            enriched_data.append({
                "url": url,
                "status_code": resp.status_code,
                "body": resp.text[:4096]
            })
        except Exception as e:
            enriched_data.append({
                "url": url,
                "error": str(e)[:512]
            })

    if enriched_data:
        request.setdefault("headers", {})
        request["headers"]["x-enrich-context"] = [{
            "key": "X-Enrich-Context",
            "value": json.dumps(enriched_data)[:8000]
        }]

    return request